3580 Value *InstCombinerImpl::foldBooleanAndOr(Value *LHS, Value *RHS,
3581                                           Instruction &I, bool IsAnd,
3582                                           bool IsLogical) {
3583   if (!LHS->getType()->isIntOrIntVectorTy(1))
3584     return nullptr;
3585 
3586   // handle (roughly):
3587   // (icmp ne (A & B), C) | (icmp ne (A & D), E)
3588   // (icmp eq (A & B), C) & (icmp eq (A & D), E)
3589   if (Value *V = foldLogOpOfMaskedICmps(LHS, RHS, IsAnd, IsLogical, Builder,
3590                                         SQ.getWithInstruction(&I)))
3591     return V;
3592 
3593   if (auto *LHSCmp = dyn_cast<ICmpInst>(LHS))
3594     if (auto *RHSCmp = dyn_cast<ICmpInst>(RHS))
3595       if (Value *Res = foldAndOrOfICmps(LHSCmp, RHSCmp, I, IsAnd, IsLogical))
3596         return Res;
3597 
3598   if (auto *LHSCmp = dyn_cast<FCmpInst>(LHS))
3599     if (auto *RHSCmp = dyn_cast<FCmpInst>(RHS))
3600       if (Value *Res = foldLogicOfFCmps(LHSCmp, RHSCmp, IsAnd, IsLogical))
3601         return Res;
3602 
3603   if (Value *Res = foldEqOfParts(LHS, RHS, IsAnd))
3604     return Res;
3605 
3606   auto TryFold = [&](Value *L, Value *R) -> Value * {
3607     auto *ICmpR = dyn_cast<ICmpInst>(R);
3608     if (!ICmpR)
3609       return nullptr;
3610 
3611     Value *A, *B;
3612     Instruction::BinaryOps Opcode = IsAnd ? Instruction::And : Instruction::Or;
3613 
3614     bool MatchedBitwise = match(L, m_BinOp(Opcode, m_Value(A), m_Value(B)));
3615     bool MatchedLogical =
3616         !MatchedBitwise && IsLogical &&
3617         (IsAnd ? match(L, m_LogicalAnd(m_Value(A), m_Value(B)))
3618                : match(L, m_LogicalOr(m_Value(A), m_Value(B))));
3619 
3620     if (MatchedBitwise || MatchedLogical) {
3621       for (int i = 0; i < 2; ++i) {
3622         if (MatchedLogical && i == 0)
3623           continue;
3624 
3625         Value *Inner = i == 0 ? A : B;
3626         Value *Other = i == 0 ? B : A;
3627         auto *ICmpInner = dyn_cast<ICmpInst>(Inner);
3628         if (!ICmpInner)
3629           continue;
3630 
3631         Value *Res =
3632             foldAndOrOfICmps(ICmpInner, ICmpR, I, IsAnd, IsLogical);
3633         if (!Res)
3634           continue;
3635 
3636         if (auto *ResICmp = dyn_cast<ICmpInst>(Res))
3637           ResICmp->setSameSign(false);
3638 
3639         if (IsLogical)
3640           return IsAnd ? Builder.CreateLogicalAnd(Other, Res)
3641                        : Builder.CreateLogicalOr(Other, Res);
3642 
3643         // For bitwise reconstruction, canonicalize icmp to the left (Res).
3644         return Builder.CreateBinOp(Opcode, Res, Other);
3645       }
3646     }
3647     return nullptr;
3648   };
3649 
3650   if (Value *V = TryFold(LHS, RHS))
3651     return V;
3652   if (!IsLogical)
3653     if (Value *V = TryFold(RHS, LHS))
3654       return V;
3655 
3656   return nullptr;
3657 }
