3659 static Value *foldOrOfInversions(BinaryOperator &I,
3660                                  InstCombiner::BuilderTy &Builder) {
3661   assert(I.getOpcode() == Instruction::Or &&
3662          "Simplification only supports or at the moment.");
3663 
3664   Value *Cmp1, *Cmp2, *Cmp3, *Cmp4;
3665   if (!match(I.getOperand(0), m_And(m_Value(Cmp1), m_Value(Cmp2))) ||
3666       !match(I.getOperand(1), m_And(m_Value(Cmp3), m_Value(Cmp4))))
3667     return nullptr;
3668 
3669   // Check if any two pairs of the and operations are inversions of each other.
3670   if (isKnownInversion(Cmp1, Cmp3) && isKnownInversion(Cmp2, Cmp4))
3671     return Builder.CreateXor(Cmp1, Cmp4);
3672   if (isKnownInversion(Cmp1, Cmp4) && isKnownInversion(Cmp2, Cmp3))
3673     return Builder.CreateXor(Cmp1, Cmp3);
3674 
3675   return nullptr;
3676 }
