3678 /// Match \p V as "shufflevector -> bitcast" or "extractelement -> zext -> shl"
3679 /// patterns, which extract vector elements and pack them in the same relative
3680 /// positions.
3681 ///
3682 /// \p Vec is the underlying vector being extracted from.
3683 /// \p Mask is a bitmask identifying which packed elements are obtained from the
3684 /// vector.
3685 /// \p VecOffset is the vector element corresponding to index 0 of the
3686 /// mask.
3687 static bool matchSubIntegerPackFromVector(Value *V, Value *&Vec,
3688                                           int64_t &VecOffset,
3689                                           SmallBitVector &Mask,
3690                                           const DataLayout &DL) {
3691   // First try to match extractelement -> zext -> shl
3692   uint64_t VecIdx, ShlAmt;
3693   if (match(V, m_ShlOrSelf(m_ZExtOrSelf(m_ExtractElt(m_Value(Vec),
3694                                                      m_ConstantInt(VecIdx))),
3695                            ShlAmt))) {
3696     auto *VecTy = dyn_cast<FixedVectorType>(Vec->getType());
3697     if (!VecTy)
3698       return false;
3699     auto *EltTy = dyn_cast<IntegerType>(VecTy->getElementType());
3700     if (!EltTy)
3701       return false;
3702 
3703     const unsigned EltBitWidth = EltTy->getBitWidth();
3704     const unsigned TargetBitWidth = V->getType()->getIntegerBitWidth();
3705     if (TargetBitWidth % EltBitWidth != 0 || ShlAmt % EltBitWidth != 0)
3706       return false;
3707     const unsigned TargetEltWidth = TargetBitWidth / EltBitWidth;
3708     const unsigned ShlEltAmt = ShlAmt / EltBitWidth;
3709 
3710     const unsigned MaskIdx =
3711         DL.isLittleEndian() ? ShlEltAmt : TargetEltWidth - ShlEltAmt - 1;
3712 
3713     VecOffset = static_cast<int64_t>(VecIdx) - static_cast<int64_t>(MaskIdx);
3714     Mask.resize(TargetEltWidth);
3715     Mask.set(MaskIdx);
3716     return true;
3717   }
3718 
3719   // Now try to match a bitcasted subvector.
3720   Instruction *SrcVecI;
3721   if (!match(V, m_BitCast(m_Instruction(SrcVecI))))
3722     return false;
3723 
3724   auto *SrcTy = dyn_cast<FixedVectorType>(SrcVecI->getType());
3725   if (!SrcTy)
3726     return false;
3727 
3728   Mask.resize(SrcTy->getNumElements());
3729 
3730   // First check for a subvector obtained from a shufflevector.
3731   if (isa<ShuffleVectorInst>(SrcVecI)) {
3732     Constant *ConstVec;
3733     ArrayRef<int> ShuffleMask;
3734     if (!match(SrcVecI, m_Shuffle(m_Value(Vec), m_Constant(ConstVec),
3735                                   m_Mask(ShuffleMask))))
3736       return false;
3737 
3738     auto *VecTy = dyn_cast<FixedVectorType>(Vec->getType());
3739     if (!VecTy)
3740       return false;
3741 
3742     const unsigned NumVecElts = VecTy->getNumElements();
3743     bool FoundVecOffset = false;
3744     for (unsigned Idx = 0; Idx < ShuffleMask.size(); ++Idx) {
3745       if (ShuffleMask[Idx] == PoisonMaskElem)
3746         return false;
3747       const unsigned ShuffleIdx = ShuffleMask[Idx];
3748       if (ShuffleIdx >= NumVecElts) {
3749         const unsigned ConstIdx = ShuffleIdx - NumVecElts;
3750         auto *ConstElt =
3751             dyn_cast<ConstantInt>(ConstVec->getAggregateElement(ConstIdx));
3752         if (!ConstElt || !ConstElt->isNullValue())
3753           return false;
3754         continue;
3755       }
3756 
3757       if (FoundVecOffset) {
3758         if (VecOffset + Idx != ShuffleIdx)
3759           return false;
3760       } else {
3761         if (ShuffleIdx < Idx)
3762           return false;
3763         VecOffset = ShuffleIdx - Idx;
3764         FoundVecOffset = true;
3765       }
3766       Mask.set(Idx);
3767     }
3768     return FoundVecOffset;
3769   }
3770 
3771   // Check for a subvector obtained as an (insertelement V, 0, idx)
3772   uint64_t InsertIdx;
3773   if (!match(SrcVecI,
3774              m_InsertElt(m_Value(Vec), m_Zero(), m_ConstantInt(InsertIdx))))
3775     return false;
3776 
3777   auto *VecTy = dyn_cast<FixedVectorType>(Vec->getType());
3778   if (!VecTy)
3779     return false;
3780   VecOffset = 0;
3781   bool AlreadyInsertedMaskedElt = Mask.test(InsertIdx);
3782   Mask.set();
3783   if (!AlreadyInsertedMaskedElt)
3784     Mask.reset(InsertIdx);
3785   return true;
3786 }
